package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;

import java.io.IOException;
import java.io.Writer;
import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testPrinterReturnsCSVPrinter() throws IOException {
        CSVPrinter printer = csvFormat.printer();
        assertNotNull(printer);
    }

    @Test
    void testPrinterWritesToSystemOut() throws Exception {
        CSVPrinter printer = csvFormat.printer();

        Field outField = CSVPrinter.class.getDeclaredField("out");
        outField.setAccessible(true);
        Object outObject = outField.get(printer);

        assertTrue(outObject instanceof Writer);

        // Since CSVPrinter wraps System.out in a Writer, we cannot directly assertSame.
        // Instead, we check that the underlying OutputStream is System.out via reflection.

        Field outFieldOfWriter = outObject.getClass().getDeclaredField("out");
        outFieldOfWriter.setAccessible(true);
        Object underlyingOut = outFieldOfWriter.get(outObject);

        assertSame(System.out, underlyingOut);
    }
}
